// ═══════════════════════════════════════════════════════════════
// PLAYER PRICING  (for Salary Cap mode)
// ═══════════════════════════════════════════════════════════════
// Each player's standalone dollar value, derived from peak WAR/season blended
// with rate-stat dominance so truly elite peaks (Bonds, Koufax, Pedro) command
// a premium even when raw counting WAR is modest. Exponential curve makes
// superstars scarce/expensive and role players affordable.
//   Range: ~$7 (replacement) to ~$72 (Ted Williams / inner-circle peak)
const POSITION_SCARCITY = { C:1.18, SS:1.15, '2B':1.10, CF:1.08, '3B':1.05, RF:1.00, LF:0.97, '1B':0.95, DH:0.90 };

function playerPrice(p) {
  const war = p.avgWARperYear || 3;
  const s = p.stats || {};
  let raw;
  if (p.type === 'hitter') {
    const wrc = s.wrcPlus || 100;
    const rateFactor = Math.max(0.6, Math.pow(wrc / 130, 1.3));
    const scarcity = POSITION_SCARCITY[p.position] || 1.0; // up-the-middle bats cost a premium
    raw = Math.pow(war, 1.55) * 0.95 * rateFactor * scarcity;
  } else if (p.role === 'SP') {
    const era = s.era || 4.0, fip = s.fip || 4.0;
    const quality = (4.20 - (0.6*fip + 0.4*era)) / 1.5;
    const rateFactor = Math.max(0.7, 1 + quality * 0.55);
    raw = Math.pow(war, 1.5) * 1.05 * rateFactor;
  } else {
    const era = s.era || 3.5, fip = s.fip || 3.5;
    const quality = (3.80 - (0.6*fip + 0.4*era)) / 1.4;
    const rateFactor = Math.max(0.7, 1 + quality * 0.5);
    raw = Math.pow(war, 1.4) * 2.0 * rateFactor + 2;
  }
  return Math.max(3, Math.round(raw));
}

// Budget for Salary Cap mode. With the all-time-greats sample pool every roster is
// strong (there are no scrubs to draft), so the budget mainly shapes WHICH stars you
// get. Once real Fangraphs data is loaded — full of replacement-level players and
// journeyman arms — this same budget forces genuine sacrifices: roster real scrubs to
// afford your stars, and a poor draft yields a losing team. $390 is tuned to bite then.
const SALARY_CAP_BUDGET = 250;

// ═══════════════════════════════════════════════════════════════
// SIMULATION ENGINE  (v2 — grounded in real sabermetrics)
// ═══════════════════════════════════════════════════════════════
//
// DESIGN PHILOSOPHY:
// • Offense is driven by wRC+, which is ALREADY park- and era-adjusted and
//   weights each event by its real run value. A team's runs scored scales
//   multiplicatively with its average wRC+ (a 125 wRC+ team scores ~25% more
//   than league average — this is true by the stat's definition).
// • Lineup construction (batting order) adds a small ±4% on top, matching
//   research from "The Book" showing optimal vs poor order ≈ 2-3% of runs.
// • Pitching uses a 60/40 FIP/ERA blend (FIP is predictive, ERA is observed),
//   converted to runs allowed with an unearned-run factor, weighted by
//   rotation slot (ace pitches most) and bullpen leverage (closer matters most).
// • Defense subtracts runs saved (dWAR), scaled by positional importance.
// • Win% uses Pythagenpat — the most accurate Pythagorean variant, with a
//   dynamic exponent that self-adjusts to the run environment.
// • A 162-game season is Monte-Carlo simulated; we take the median of several
//   runs to give a stable-but-realistic result.

// Positional defensive importance (how much a great glove matters at the spot).
// Scaled so SS/C = full credit, corner spots and DH matter least.
const DEFENSE_MULT = { C:1.0, SS:1.0, CF:0.9, '2B':0.85, '3B':0.6, RF:0.5, LF:0.4, '1B':0.3, DH:0 };

// Pitching era adjustment: 1960s ERAs were artificially low (high mound, large
// strike zone, pitcher's era), so we inflate their effective runs allowed.
// wRC+ already handles era for HITTERS, so hitters need no era factor here.
const ERA_PITCH_ADJ = {
  '1940s':0.96, '1950s':0.97, '1960s':1.06, '1970s':1.00, '1980s':1.00,
  '1990s':0.97, '2000s':1.00, '2010s':1.00, '2020s':1.00,
};

const LG_AVG_RPG = 4.30; // Neutral modern run environment

// ── OFFENSE: average wRC+ → runs per game ────────────────────────
// Multiplicative below 140 wRC+ (matches real team seasons exactly).
// Above 140, apply diminishing returns — no real team has ever sustained
// a pure all-peak lineup, and the 1927 Yankees (~6.3 R/G) are the ceiling.
function offenseFromWRC(avgWRC) {
  // Above 140: diminishing returns (no real lineup sustains pure peak; 1927 Yankees ~6.3 R/G ceiling)
  if (avgWRC >= 140) return LG_AVG_RPG * 1.40 + (avgWRC - 140) * 0.0163 * 0.55;
  // 90-140: clean multiplicative (validated vs real seasons — 2023 Braves, league avgs)
  if (avgWRC >= 90)  return LG_AVG_RPG * (avgWRC / 100);
  // Below 90: steeper crater. A 75-85 wRC+ offense is historically awful
  // (2010 Mariners: 85 wRC+, scored 3.17 R/G, went 61-101). Punting offense must hurt.
  const at90 = LG_AVG_RPG * 0.90;
  return Math.max(2.0, at90 - (90 - avgWRC) * 0.065);
}

// Returns runs/game plus the construction adjustment and supporting detail.
function lineupRunsPerGame(lineup) {
  const valid = lineup.filter(Boolean);
  if (valid.length < 9) return { rpg:0, construction:0, baseRPG:0, avgWRC:100 };

  const avgWRC = valid.reduce((s,p)=>s+(p.stats?.wrcPlus||100),0)/valid.length;
  const baseRPG = offenseFromWRC(avgWRC);

  // Lineup construction signal (batting order quality + team plate discipline)
  let c = 0;
  const topOBP = ((valid[0]?.stats?.obp||0)+(valid[1]?.stats?.obp||0))/2;
  if (topOBP>0.390) c+=0.025; else if (topOBP>0.360) c+=0.012; else if (topOBP<0.310) c-=0.025;

  const midSLG = ((valid[2]?.stats?.slg||0)+(valid[3]?.stats?.slg||0)+(valid[4]?.stats?.slg||0))/3;
  if (midSLG>0.560) c+=0.022; else if (midSLG>0.500) c+=0.010; else if (midSLG<0.400) c-=0.018;

  // Whole-lineup OBP: getting on base is the engine of scoring. Punishing all-or-nothing
  // power stacks that ignore OBP (since wRC+ alone treats them as equal to balanced bats).
  const teamOBP = valid.reduce((s,p)=>s+(p.stats?.obp||0),0)/valid.length;
  if (teamOBP>0.370) c+=0.015; else if (teamOBP<0.315) c-=0.020;

  // Penalty: best power hitter wasted leading off or at the bottom
  const slgs = valid.map(p=>p.stats?.slg||0);
  const maxSLG = Math.max(...slgs), maxSpot = slgs.indexOf(maxSLG);
  if (maxSLG>0.550 && (maxSpot===0 || maxSpot>=6)) c-=0.015;

  // Penalty: lowest-OBP hitter batting leadoff
  const obps = valid.map(p=>p.stats?.obp||0);
  const minOBP = Math.min(...obps);
  if ((valid[0]?.stats?.obp||0)===minOBP && minOBP<0.320) c-=0.012;

  // Bonus: speed at the top of the order
  const topBSR = (valid[0]?.stats?.bsr||0)+(valid[1]?.stats?.bsr||0);
  if (topBSR>6) c+=0.008;

  c = Math.max(-0.055, Math.min(0.04, c)); // penalty up to -5.5%, bonus capped at +4%
  return { rpg: baseRPG*(1+c), construction:c, baseRPG, avgWRC };
}

// ── PITCHER: FIP/ERA blend → runs allowed per 9 ──────────────────
// 60% FIP (what the pitcher controls) + 40% ERA (what actually happened),
// era-adjusted, then ×1.045 to convert earned runs to total runs (unearned).
function pitcherRA9(p) {
  const s = p.stats;
  const fip = s.fip || 4.20, era = s.era || 4.20;
  return (0.60*fip + 0.40*era) * (ERA_PITCH_ADJ[p.decade]||1.0) * 1.045;
}

// Combine the full staff into a team runs-allowed-per-game figure.
function staffRunsAllowedPerGame(starters, relievers, lineup) {
  // Starters cover ~62% of innings, weighted by rotation slot (SP1 throws most)
  let spRA = 4.30;
  if (starters.length > 0) {
    const w = [0.245,0.225,0.205,0.17,0.155].slice(0, starters.length);
    const ws = w.reduce((a,b)=>a+b,0);
    spRA = starters.reduce((s,p,i)=>s+pitcherRA9(p)*(w[i]||0.15),0)/ws;
  }
  // Relievers cover ~38%, weighted by leverage. Less top-heavy than before so a single
  // elite closer can't dominate 38% of innings (he only throws ~70 of them).
  let rpRA = 4.10;
  if (relievers.length > 0) {
    const sorted = [...relievers].sort((a,b)=>pitcherRA9(a)-pitcherRA9(b));
    const lev = [0.30,0.27,0.23,0.20].slice(0, sorted.length);
    const ws = lev.reduce((a,b)=>a+b,0);
    rpRA = sorted.reduce((s,p,i)=>s+pitcherRA9(p)*(lev[i]||0.20),0)/ws;
  }
  let ra = 0.62*spRA + 0.38*rpRA;

  // Defense: subtract runs saved per game. Divisor 110 (not 162) so the gap between
  // an elite up-the-middle defense and a corner-stacked butcher unit is ~0.3-0.4 RA/G.
  const valid = lineup.filter(Boolean);
  let defPerGame = 0;
  valid.forEach(p => {
    const pos = p.assignedPos || p.position;
    if (pos === 'DH') return;
    defPerGame += ((p.stats?.dwar||0) * (DEFENSE_MULT[pos]||0.5)) / 110;
  });
  ra -= defPerGame;

  // DIMINISHING RETURNS: stacking aces can't push a full-season staff to absurd lows.
  // No real rotation has sustained sub-2.7 RA over 162 games (1966 Dodgers 2.87,
  // 2018 Astros 3.16 are the gold standard). Below 3.2 RA, only 55% of further gains count.
  if (ra < 3.2) {
    const excess = 3.2 - ra;
    ra = 3.2 - excess * 0.55;
  }
  // Hard floor 2.4 — still better than any real team's full season, but reachable only by a perfect staff.
  return Math.max(2.4, ra);
}

// ── PYTHAGENPAT WIN EXPECTANCY ───────────────────────────────────
// Dynamic exponent = (RS + RA)^0.287 — the most accurate Pythagorean variant,
// self-adjusting to the run environment (Smyth/Patriot).
function winExpectancy(rpg, rapg) {
  const r = Math.max(0.5, rpg), a = Math.max(0.5, rapg);
  const exp = Math.pow(r + a, 0.287);
  return Math.pow(r, exp) / (Math.pow(r, exp) + Math.pow(a, exp));
}

// ── LINEUP SYNERGY (display only) ────────────────────────────────
// Surfaces WHY the construction adjustment is what it is, for the results
// screen. The actual run impact is computed in lineupRunsPerGame.
function lineupSynergy(lineup) {
  const bonuses = [], valid = lineup.filter(Boolean);
  if (valid.length < 9) return { total:0, bonuses };

  const { construction } = lineupRunsPerGame(lineup);
  const lo = valid[0]?.stats?.obp || 0;
  const cu = valid[3];
  const cuHR = cu?.stats?.hr || 0, cuSLG = cu?.stats?.slg || 0;
  const topOBP = (lo + (valid[1]?.stats?.obp||0))/2;
  const midSLG = ((valid[2]?.stats?.slg||0)+(cuSLG)+(valid[4]?.stats?.slg||0))/3;

  if (topOBP > 0.390)      bonuses.push({label:'🔥 Elite OBP at Top of Order',    val:'+', pos:true});
  else if (topOBP > 0.360) bonuses.push({label:'✅ Strong OBP at Top',            val:'+', pos:true});
  else if (topOBP < 0.310) bonuses.push({label:'⚠️ Weak OBP at Top of Order',     val:'−', pos:false});

  if (midSLG > 0.560)      bonuses.push({label:'💪 Dominant Power in the Middle',  val:'+', pos:true});
  else if (midSLG > 0.500) bonuses.push({label:'✅ Strong Middle-of-Order Power',  val:'+', pos:true});
  else if (midSLG < 0.400) bonuses.push({label:'⚠️ Light Power in the Middle',     val:'−', pos:false});

  const slgs = valid.map(p=>p.stats?.slg||0), maxSLG=Math.max(...slgs), maxSpot=slgs.indexOf(maxSLG);
  if (maxSLG>0.550 && (maxSpot===0||maxSpot>=6)) bonuses.push({label:'⚠️ Power Hitter Wasted Out of the Middle', val:'−', pos:false});

  const topBSR = (valid[0]?.stats?.bsr||0)+(valid[1]?.stats?.bsr||0);
  if (topBSR>6) bonuses.push({label:'⚡ Elite Speed at Top of Order', val:'+', pos:true});

  // Express the net construction effect as an R/G figure for the results screen
  const total = construction; // fraction
  return { total, bonuses, constructionPct: construction };
}

// ── ERA DIVERSITY (game mechanic) ────────────────────────────────
// Win% multiplier rewarding drafting across history, not a baseball reality.
function eraDiversityBonus(players) {
  const n = new Set(players.map(p=>p.decade)).size;
  if (n >= 6) return { mult:1.020, label:`🏛️ ${n} Eras — Max Diversity Bonus` };
  if (n >= 4) return { mult:1.010, label:`📅 ${n} Eras — Strong Diversity` };
  if (n >= 3) return { mult:1.003, label:`📅 ${n} Eras — Minimum Met` };
  return        { mult:0.975,        label:`⚠️ Only ${n} Era(s) — Diversity Penalty` };
}

function simulate(roster, lineup, decadeMode=false) {
  const hitters = lineup.filter(Boolean);
  if (hitters.length < 9) return null;

  const starters  = Object.entries(roster).filter(([k])=>k.startsWith('SP')).map(([,v])=>v).filter(Boolean);
  const relievers = Object.entries(roster).filter(([k])=>k.startsWith('RP')).map(([,v])=>v).filter(Boolean);
  const allPlayers = Object.values(roster).filter(Boolean);

  // Offense
  const off = lineupRunsPerGame(hitters);
  let rpg = off.rpg;

  // Pitching + defense
  let rapg = staffRunsAllowedPerGame(starters, relievers, hitters);

  // Era diversity (win% multiplier) 
  const era = eraDiversityBonus(allPlayers);
  const eraMult = decadeMode ? 1.0 : era.mult;

  // Pythagenpat win expectancy, nudged by era diversity
  const rawWinPct = winExpectancy(rpg, rapg);
  const winPct = Math.min(rawWinPct * eraMult, 0.992); // 0.992 ≈ 161 wins ceiling

  // Monte-Carlo a 162-game season, median of 7 runs for stability
  const sims = Array.from({length:7}, () => {
    let w=0; for(let i=0;i<162;i++) if(Math.random()<winPct) w++; return w;
  }).sort((a,b)=>a-b);
  const wins = sims[3];

  const syn = lineupSynergy(hitters);
  const benchmark = HISTORICAL_BENCHMARKS.find(b=>wins>=b.wins) || HISTORICAL_BENCHMARKS[HISTORICAL_BENCHMARKS.length-1];

  return {
    wins, losses:162-wins, winPct, rawWinPct,
    rpg: Math.round(rpg*10)/10,
    rapg: Math.round(rapg*10)/10,
    avgWRC: Math.round(off.avgWRC),
    constructionPct: off.construction,
    benchmark,
    synBonuses: syn.bonuses,
    era,
  };
}

function getLineupFeedback(lineup) {
  const msgs = [], valid = lineup.filter(Boolean);
  if (!valid.length) return msgs;

  // Spot 1 — leadoff OBP
  const lo = valid[0];
  if (lo) {
    if (lo.stats?.obp < .330) msgs.push({type:'warn', msg:`${lo.name} has low OBP for leadoff (.${String(Math.round(lo.stats.obp*1000)).padStart(3,'0')})`});
    else if (lo.stats?.obp > .390) msgs.push({type:'ok', msg:`${lo.name} is an elite leadoff hitter (.${String(Math.round(lo.stats.obp*1000)).padStart(3,'0')} OBP)`});
  }

  // Spot 2 — should have OBP not just power
  const s2 = valid[1];
  if (s2 && (s2.stats?.hr||0) > 40 && (s2.stats?.obp||0) < .360)
    msgs.push({type:'warn', msg:`${s2.name} is a pure slugger batting 2nd — consider moving down`});

  // Spots 3-4 — power in the middle
  const s3 = valid[2], cu = valid[3];
  if (s3 && (s3.stats?.wrcPlus||100) < 115) msgs.push({type:'warn', msg:`${s3.name} is below average for the 3-hole (wRC+ ${s3.stats?.wrcPlus})`});
  if (cu) {
    if ((cu.stats?.hr||0) < 25) msgs.push({type:'warn', msg:`${cu.name} lacks cleanup power (${cu.stats?.hr} HR)`});
    else if ((cu.stats?.hr||0) > 40) msgs.push({type:'ok', msg:`${cu.name} is a dominant cleanup hitter (${cu.stats?.hr} HR)`});
  }

  // Check OBP feeding cleanup
  if (s3 && cu && (s3.stats?.obp||0) < .340 && (cu.stats?.hr||0) > 35)
    msgs.push({type:'warn', msg:`Low OBP in 3-hole means ${cu.name} often bats with nobody on`});

  // Spots 7-9 — defense/speed guys batting low is fine, sluggers here waste power
  [6,7,8].forEach(i => {
    const p = valid[i];
    if (p && (p.stats?.hr||0) > 38 && (p.stats?.obp||0) < .350)
      msgs.push({type:'warn', msg:`${p.name} is wasted in the ${i+1}-hole — move up in the order`});
  });

  // Lineup balance check
  const avgOBP = valid.reduce((s,p)=>s+(p.stats?.obp||0),0)/valid.length;
  if (avgOBP > .390) msgs.push({type:'ok', msg:`Excellent lineup OBP (.${String(Math.round(avgOBP*1000)).padStart(3,'0')} avg)`});
  else if (avgOBP < .330) msgs.push({type:'warn', msg:`Low overall lineup OBP — consider more patient hitters`});

  return msgs;
}

// ═══════════════════════════════════════════════════════════════
// CSV PROCESSING
// ═══════════════════════════════════════════════════════════════
function parseCSV(text) {
  const lines=text.trim().split('\n'); if(lines.length<2) return [];
  function pl(line){const r=[];let c='',q=false;for(const ch of line){if(ch==='"')q=!q;else if(ch===','&&!q){r.push(c.trim());c='';}else c+=ch;}r.push(c.trim());return r;}
  const headers=pl(lines[0]);
  return lines.slice(1).map(l=>{const v=pl(l),o={};headers.forEach((h,i)=>{o[h.trim()]=v[i]||'';});return o;}).filter(r=>r[headers[0]]);
}
function getDecade(y){const n=parseInt(y);if(n<1950)return'1940s';if(n<1960)return'1950s';if(n<1970)return'1960s';if(n<1980)return'1970s';if(n<1990)return'1980s';if(n<2000)return'1990s';if(n<2010)return'2000s';if(n<2020)return'2010s';return'2020s';}
function nPos(p){const m={C:'C','1B':'1B','2B':'2B','3B':'3B','SS':'SS','LF':'LF','CF':'CF','RF':'RF','DH':'DH','OF':'LF',SP:'SP',RP:'RP',CL:'RP',P:'SP'};return m[(p||'').toUpperCase().trim()]||'DH';}
function getEligible(pos,role,gs,g){
  const p=pos||'DH'; const r=role||'';
  if(r==='SP'||p==='SP') return ['SP'];
  if(r==='RP'||p==='RP') return ['RP'];
  const map={C:['C','DH'],'1B':['1B','DH'],'2B':['2B','DH'],'3B':['3B','DH'],SS:['SS','3B','DH'],LF:['LF','CF','RF','DH'],CF:['CF','LF','RF','DH'],RF:['RF','LF','CF','DH'],DH:['DH']};
  return map[p]||['DH'];
}
// ── SMART PEAK FINDER ────────────────────────────────────────────
// Finds a player's true career peak (best 1-3 consecutive seasons),
// crosses decade boundaries freely, then generates one card per
// decade the peak years overlap — so a 1978-1980 peak appears in
// BOTH the 1970s AND 1980s pools.
//
// Sample-size confidence:
//   3 seasons  → full WAR/yr, no adjustment
//   2 seasons  → 92% of WAR/yr (small penalty, still strong)
//   1 season   → 80% of WAR/yr (one year could be a fluke)
//
// Team tagging: a player's card for a given decade uses the team
// they played for the MOST in those peak years. If they only
// spent 1 year with a team in a decade, that team still shows
// the card — the player really was there.

function buildCards(seasons) {
  // Group all seasons by player name
  const byPlayer = {};
  seasons.forEach(s => {
    const key = s.name;
    if (!byPlayer[key]) byPlayer[key] = [];
    byPlayer[key].push(s);
  });

  const cards = [];

  Object.entries(byPlayer).forEach(([name, segs]) => {
    if (!segs.length) return;
    segs.sort((a, b) => a.season - b.season);

    const isH = segs[0].type === 'hitter';

    // ── Find the best peak window (1, 2, or 3 seasons) ──
    // We try 3-year windows first (within 4 calendar years),
    // then 2-year, then 1-year as last resort.
    let bestWindow = null;
    let bestWAR = -Infinity;

    // 3-year windows (consecutive seasons within a 4-year span)
    for (let i = 0; i <= segs.length - 3; i++) {
      const w = segs.slice(i, i + 3);
      if (w[2].season - w[0].season > 4) continue;
      const tot = w.reduce((s, x) => s + x.war, 0);
      if (tot > bestWAR) { bestWAR = tot; bestWindow = w; }
    }

    // 2-year windows (if no 3-year found, or check if any 2-yr beats it)
    if (segs.length >= 2) {
      for (let i = 0; i <= segs.length - 2; i++) {
        const w = segs.slice(i, i + 2);
        if (w[1].season - w[0].season > 2) continue;
        const tot = w.reduce((s, x) => s + x.war, 0) * 0.92; // 2-yr confidence
        if (tot > bestWAR) { bestWAR = tot; bestWindow = w; }
      }
    }

    // 1-year fallback
    if (!bestWindow || segs.length === 1) {
      const best1 = segs.reduce((a, b) => b.war > a.war ? b : a);
      const tot = best1.war * 0.80; // 1-yr confidence
      if (tot > bestWAR) { bestWAR = tot; bestWindow = [best1]; }
    }

    if (!bestWindow || !bestWindow.length) return;

    const sampleSize = bestWindow.length;
    const rawWARperYear = bestWAR / sampleSize;
    const avg = k => bestWindow.reduce((s, x) => s + (x.stats?.[k] || 0), 0) / sampleSize;
    const peakYears = bestWindow.map(s => s.season);

    // ── Determine which decades the peak years span ──
    const decadesHit = [...new Set(peakYears.map(y => getDecade(y)))];

    // ── For each decade this peak overlaps, build a card ──
    decadesHit.forEach(decade => {
      // Find the team the player played for most in this decade
      // (using all their seasons in that decade, not just peak)
      const decSeasons = segs.filter(s => s.decade === decade);
      const teamCounts = {};
      decSeasons.forEach(s => { teamCounts[s.team] = (teamCounts[s.team] || 0) + 1; });
      // Fall back to peak window team if no seasons recorded in this decade
      // (can happen when peak straddles a boundary)
      const team = Object.keys(teamCounts).length
        ? Object.entries(teamCounts).sort((a, b) => b[1] - a[1])[0][0]
        : bestWindow[Math.floor(sampleSize / 2)].team;

      // Label short stints so the user knows
      const sampleNote = sampleSize === 1 ? ' (1-yr)' : sampleSize === 2 ? ' (2-yr)' : '';

      const baseId = `${name.toLowerCase().replace(/[^a-z0-9]/g, '-')}-${decade}`;

      // Avoid duplicate IDs if the same player/decade was already added
      if (cards.some(c => c.id === baseId)) return;

      const card = {
        id: baseId,
        name: name + sampleNote,
        displayName: name,
        team,
        decade,
        sampleSize,
        position: segs[0].position,
        eligiblePositions: segs[0].eligiblePositions || [segs[0].position],
        type: segs[0].type,
        role: segs[0].role || null,
        peakYears,
        avgWARperYear: Math.round(rawWARperYear * 10) / 10,
      };

      if (isH) {
        card.stats = {
          avg:     Math.round(avg('avg') * 1000) / 1000,
          hr:      Math.round(avg('hr')),
          obp:     Math.round(avg('obp') * 1000) / 1000,
          slg:     Math.round(avg('slg') * 1000) / 1000,
          wrcPlus: Math.round(avg('wrcPlus')),
          bsr:     Math.round(avg('bsr') * 10) / 10,
          dwar:    Math.round(avg('dwar') * 10) / 10,
        };
      } else {
        const avgIP = avg('ip');
        const avgWAR = avg('war');
        card.stats = {
          era:  Math.round(avg('era') * 100) / 100,
          whip: Math.round(avg('whip') * 100) / 100,
          k9:   Math.round(avg('k9') * 10) / 10,
          fip:  Math.round(avg('fip') * 100) / 100,
          ip:   Math.round(avgIP),
          war:  Math.round(avgWAR * 10) / 10,
          war9: avgIP > 0 ? Math.round((avgWAR / avgIP * 9) * 100) / 100 : 0,
        };
      }

      cards.push(card);
    });
  });

  return cards;
}

function processCSVFiles(files) {
  // Collect ALL seasons first (across all decade files) before building cards
  // This ensures peak windows can cross decade boundaries correctly
  let hS = [], pS = [];
  files.forEach(f => {
    const rows = parseCSV(f.content);
    const dec = f.decade;
    const isH = f.type === 'hitter';
    rows.forEach(row => {
      const name = row['Name'] || '', team = row['Team'] || '';
      const season = parseInt(row['Season'] || 0);
      const war = parseFloat(row['WAR'] || 0);
      if (!name || war <= 0) return;
      if (isH) {
        const pos = nPos(row['Pos'] || row['pos'] || '');
        const elig = getEligible(pos, null, 0, 1);
        hS.push({
          name, team, season,
          decade: dec || getDecade(season),
          type: 'hitter', role: null,
          position: pos, eligiblePositions: elig, war,
          stats: {
            avg: parseFloat(row['AVG'] || 0), hr: parseFloat(row['HR'] || 0),
            obp: parseFloat(row['OBP'] || 0), slg: parseFloat(row['SLG'] || 0),
            wrcPlus: parseFloat(row['wRC+'] || 100), bsr: parseFloat(row['BsR'] || 0),
            dwar: parseFloat(row['Def'] || row['dWAR'] || 0),
          }
        });
      } else {
        const ip = parseFloat(row['IP'] || 0), gs = parseFloat(row['GS'] || 0), g = parseFloat(row['G'] || 1);
        const role = (g > 0 && gs / g > .5) ? 'SP' : 'RP';
        pS.push({
          name, team, season,
          decade: dec || getDecade(season),
          type: 'pitcher', role, position: role, eligiblePositions: [role], war,
          stats: {
            era: parseFloat(row['ERA'] || 4.5), whip: parseFloat(row['WHIP'] || 1.35),
            k9: parseFloat(row['K/9'] || 7), fip: parseFloat(row['FIP'] || 4.2),
            ip, war, war9: ip > 0 ? (war / ip * 9) : 0,
          }
        });
      }
    });
  });
  // Pass ALL seasons at once so peak finder can cross decade lines
  return [...buildCards(hS), ...buildCards(pS)];
}

// ═══════════════════════════════════════════════════════════════
// HELPERS
// ═══════════════════════════════════════════════════════════════
function randTeamDecade(){
  const dec=DECADES[Math.floor(Math.random()*DECADES.length)];
  const teams=TEAMS_BY_DECADE[dec];
  return {team:teams[Math.floor(Math.random()*teams.length)],decade:dec};
}
function todaySeed(){return new Date().toDateString().split('').reduce((a,c)=>a+c.charCodeAt(0),0);}

function getFilledPositions(roster){
  const filled={};
  Object.entries(roster).forEach(([slotId,player])=>{
    if(player && player.assignedPos) filled[player.assignedPos]=(filled[player.assignedPos]||0)+1;
  });
  return filled;
}

function getRosterCounts(roster){
  let h=0,sp=0,rp=0;
  Object.entries(roster).forEach(([slotId,player])=>{
    if(!player) return;
    if(player.type==='hitter') h++;
    else if(player.role==='SP') sp++;
    else rp++;
  });
  return {h,sp,rp};
}

function getNextSlotId(roster){
  return ROSTER_NEEDS.find(s=>!roster[s.id])?.id||null;
}

// Minimum cost to fill all remaining roster slots, by category, from the available
// player pool. Used in Salary Cap mode to compute a safe budget reserve so a player
// can never strand themselves unable to complete a legal 18-man roster.
function minCostToFillRemaining(players, roster, excludePlayer){
  const drafted=new Set(Object.values(roster).filter(Boolean).map(p=>p.id));
  if(excludePlayer) drafted.add(excludePlayer.id);
  const need=getNeededPositions(roster);
  // After excludePlayer is hypothetically drafted, reduce the need it would fill
  if(excludePlayer){
    if(excludePlayer.assignedPos==='SP'||excludePlayer.role==='SP') need.sp=Math.max(0,need.sp-1);
    else if(excludePlayer.assignedPos==='RP'||excludePlayer.role==='RP') need.rp=Math.max(0,need.rp-1);
    else if(excludePlayer.assignedPos) need.hitter=need.hitter.filter(p=>p!==excludePlayer.assignedPos);
  }
  const avail=players.filter(p=>!drafted.has(p.id));
  const cheapestN=(arr,n)=>arr.map(playerPrice).sort((a,b)=>a-b).slice(0,n).reduce((s,x)=>s+x,0);
  // Hitters: need.hitter is a list of specific positions; for each, find cheapest eligible
  let hitCost=0;
  const usedIds=new Set();
  need.hitter.forEach(pos=>{
    const elig=avail.filter(p=>p.type==='hitter'&&!usedIds.has(p.id)&&(p.eligiblePositions||[]).includes(pos))
                    .sort((a,b)=>playerPrice(a)-playerPrice(b));
    if(elig.length){ hitCost+=playerPrice(elig[0]); usedIds.add(elig[0].id); }
    else { // fallback: any cheapest hitter
      const any=avail.filter(p=>p.type==='hitter'&&!usedIds.has(p.id)).sort((a,b)=>playerPrice(a)-playerPrice(b));
      if(any.length){ hitCost+=playerPrice(any[0]); usedIds.add(any[0].id); }
    }
  });
  const spCost=cheapestN(avail.filter(p=>p.role==='SP'),need.sp);
  const rpCost=cheapestN(avail.filter(p=>p.role==='RP'),need.rp);
  return hitCost+spCost+rpCost;
}

// Which positions are still needed?
function getNeededPositions(roster){
  const hitterSlots=['C','1B','2B','3B','SS','LF','CF','RF','DH'];
  const filled=new Set(Object.values(roster).filter(Boolean).map(p=>p.assignedPos));
  const needed={hitter:[],sp:0,rp:0};
  hitterSlots.forEach(p=>{if(!filled.has(p))needed.hitter.push(p);});
  let sp=0,rp=0;
  Object.entries(roster).forEach(([k,v])=>{if(v&&v.role==='SP')sp++;if(v&&v.role==='RP')rp++;});
  needed.sp=Math.max(0,5-sp); needed.rp=Math.max(0,4-rp);
  return needed;
}

// ═══════════════════════════════════════════════════════════════
// SLOT MACHINE
// ═══════════════════════════════════════════════════════════════
function SlotMachine({spinning,result,decadeMode,lockedDecade,rerollMode}){
  const [disp,setDisp]=useState({team:'???',decade:'????s'});
  const ref=useRef(null);
  // In decade mode spinning for a team: only cycle through teams in the locked decade
  useEffect(()=>{
    if(spinning){
      if(decadeMode&&lockedDecade){
        // Locked decade: only spin teams
        const teams=TEAMS_BY_DECADE[lockedDecade]||[];
        ref.current=setInterval(()=>setDisp({team:teams[Math.floor(Math.random()*teams.length)],decade:lockedDecade}),80);
      } else if(decadeMode&&!lockedDecade){
        // Pre-lock: only spin decades
        ref.current=setInterval(()=>setDisp({team:'',decade:DECADES[Math.floor(Math.random()*DECADES.length)]}),80);
      } else if(rerollMode==='team'){
        // Team reroll: freeze decade from result, only cycle teams
        const dec=result?.decade||disp.decade;
        const teams=TEAMS_BY_DECADE[dec]||[];
        setDisp(d=>({...d,decade:dec})); // lock decade immediately
        ref.current=setInterval(()=>setDisp(d=>({team:teams[Math.floor(Math.random()*teams.length)],decade:dec})),80);
      } else if(rerollMode==='decade'){
        // Decade reroll: freeze team from result, only cycle decades
        const frozenTeam=result?.team||disp.team;
        setDisp(d=>({...d,team:frozenTeam})); // lock team immediately
        ref.current=setInterval(()=>setDisp(d=>({team:frozenTeam,decade:DECADES[Math.floor(Math.random()*DECADES.length)]})),80);
      } else {
        ref.current=setInterval(()=>setDisp(randTeamDecade()),80);
      }
    } else {
      clearInterval(ref.current);
      if(result&&result.team) setDisp(result);
    }
    return()=>clearInterval(ref.current);
  },[spinning,result,decadeMode,lockedDecade,rerollMode]);
  // In decade mode after lock: only show the team spinning, decade is shown in header badge
  const teamOnly=decadeMode&&lockedDecade;
  const decadeOnly=decadeMode&&!lockedDecade;
  return(
    <div style={{textAlign:'center',background:'rgba(6,12,24,0.95)',border:'2px solid #1e3a5f',borderRadius:16,padding:'16px 24px',width:'100%',maxWidth:360}}>
      <div style={{fontSize:9,letterSpacing:4,color:'#334155',marginBottom:10}}>SLOT MACHINE</div>
      <div style={{display:'flex',alignItems:'center',justifyContent:'center',gap:10}}>
        {!decadeOnly&&<div style={{fontSize:24,fontWeight:900,color:spinning?'#1e3a5f':'#f59e0b',transition:'color .15s',fontFamily:'Georgia,serif'}}>{disp.team||'???'}</div>}
        {!teamOnly&&!decadeOnly&&<div style={{fontSize:18,color:'#0f1f35'}}>·</div>}
        {!teamOnly&&<div style={{fontSize:24,fontWeight:900,color:spinning?'#1e3a5f':'#60a5fa',transition:'color .15s',fontFamily:'Georgia,serif'}}>{disp.decade}</div>}
      </div>
      {!spinning&&result&&result.team&&<div style={{fontSize:11,color:'#475569',marginTop:10}}>Pick any player from this pool — you choose the position</div>}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════
// PLAYER ROW (table-based pool display)
// ═══════════════════════════════════════════════════════════════
function PlayerCard({player,onPick,mode,filledPositions,neededPositions,salaryMode,budgetLeft,slotsLeft,players,roster,isMobile}){
  const [selPos,setSelPos]=useState(null);
  const [expanded,setExpanded]=useState(false);
  const isH=player.type==='hitter';
  const s=player.stats;
  const price=playerPrice(player);

  const availablePositions=player.eligiblePositions.filter(pos=>{
    if(pos==='SP') return neededPositions.sp>0;
    if(pos==='RP') return neededPositions.rp>0;
    return neededPositions.hitter.includes(pos);
  });

  const chosen=selPos||availablePositions[0]||null;

  let reserveNeeded=0, affordable=true;
  if(salaryMode && chosen && players && roster){
    try {
      const candidate={...player,assignedPos:chosen};
      reserveNeeded=minCostToFillRemaining(players,roster,candidate);
      affordable=(price<=budgetLeft-reserveNeeded);
    } catch(e){ affordable=true; }
  }
  const canPick=availablePositions.length>0 && affordable;

  function handlePick(pos){
    const p=pos||chosen;
    if(!p||!canPick) return;
    onPick({...player,assignedPos:p});
  }

  const fmt3=n=>n!=null?`.${String(Math.round(n*1000)).padStart(3,'0')}`:'—';
  const hi=(v,good)=>good?{color:'#f59e0b',fontWeight:700}:{color:'#cbd5e1'};

  // Hitter stat columns
  const hCols=[
    {k:'WAR',v:player.avgWARperYear,good:player.avgWARperYear>=6},
    {k:'AVG', v:fmt3(s.avg)},
    {k:'OBP', v:fmt3(s.obp), good:s.obp>=0.380},
    {k:'SLG', v:fmt3(s.slg), good:s.slg>=0.500},
    {k:'HR',  v:s.hr,        good:s.hr>=30},
    {k:'wRC+',v:s.wrcPlus,   good:s.wrcPlus>=140},
    {k:'BsR', v:(s.bsr>0?'+':'')+s.bsr},
    {k:'dWAR',v:(s.dwar>0?'+':'')+s.dwar},
  ];
  const hColsMobile=[
    {k:'WAR',v:player.avgWARperYear,good:player.avgWARperYear>=6},
    {k:'OBP', v:fmt3(s.obp), good:s.obp>=0.380},
    {k:'HR',  v:s.hr,        good:s.hr>=30},
  ];
  // Pitcher stat columns
  const pCols=[
    {k:'WAR',  v:player.avgWARperYear, good:player.avgWARperYear>=5},
    {k:'ERA',  v:s.era,   good:s.era<3.00},
    {k:'FIP',  v:s.fip,   good:s.fip<3.00},
    {k:'WHIP', v:s.whip,  good:s.whip<1.10},
    {k:'K/9',  v:s.k9,    good:s.k9>=9},
    {k:player.role==='RP'?'WAR/9':'IP', v:player.role==='RP'?s.war9:s.ip},
  ];
  const pColsMobile=[
    {k:'WAR',v:player.avgWARperYear,good:player.avgWARperYear>=5},
    {k:'ERA',v:s.era,good:s.era<3.00},
    {k:'FIP',v:s.fip,good:s.fip<3.00},
  ];
  const cols=isH?(isMobile?hColsMobile:hCols):(isMobile?pColsMobile:pCols);

  return(
    <tr style={{borderBottom:'1px solid #0a1828',opacity:canPick?1:0.35,
      transition:'background .1s',cursor:canPick?'pointer':'default'}}
      onMouseEnter={e=>{if(canPick)e.currentTarget.style.background='rgba(245,158,11,0.06)';}}
      onMouseLeave={e=>{e.currentTarget.style.background='transparent';}}>

      {/* Name + team + decade */}
      <td style={{padding:'8px 8px',minWidth:120}}>
        <div style={{display:'flex',alignItems:'center',gap:6}}>
          <span style={{fontSize:13,fontWeight:700,color:'#f1f5f9',whiteSpace:'nowrap'}}>{player.name}</span>
          {player.sampleNote&&<span style={{fontSize:9,background:'rgba(251,146,60,0.15)',border:'1px solid rgba(251,146,60,0.35)',color:'#fb923c',padding:'1px 4px',borderRadius:3,flexShrink:0}}>{player.sampleNote}</span>}
        </div>
        <div style={{fontSize:10,color:'#475569',marginTop:1}}>{player.team} · {player.decade}</div>
        {/* Expanded: position picker shown inline below name on mobile */}
        {expanded&&availablePositions.length>0&&(
          <div style={{display:'flex',gap:6,flexWrap:'wrap',marginTop:8,padding:'6px',background:'rgba(245,158,11,0.05)',borderRadius:8,border:'1px solid rgba(245,158,11,0.2)'}} >
            {availablePositions.map(pos=>(
              <button key={pos}
                onClick={e=>{e.preventDefault();setSelPos(pos);handlePick(pos);}}
                onTouchEnd={e=>{e.preventDefault();setSelPos(pos);handlePick(pos);}}
                style={{padding:'5px 12px',borderRadius:6,border:`1px solid ${selPos===pos?'#f59e0b':'#334155'}`,background:selPos===pos?'rgba(245,158,11,0.15)':'rgba(8,16,32,0.8)',color:selPos===pos?'#f59e0b':'#94a3b8',fontSize:12,fontWeight:700,cursor:'pointer',transition:'all .1s'}}>
                {pos}
              </button>
            ))}
          </div>
        )}
        {!canPick&&availablePositions.length===0&&(
          <div style={{fontSize:10,color:'#334155',marginTop:2,fontStyle:'italic'}}>Position filled</div>
        )}
        {!canPick&&salaryMode&&!affordable&&availablePositions.length>0&&(
          <div style={{fontSize:10,color:'#ef4444',marginTop:2}}>Can't afford (${price})</div>
        )}
      </td>

      {/* Position badge */}
      <td style={{padding:'10px 8px',textAlign:'center'}}>
        {availablePositions.length===1?(
          <span style={{fontSize:11,fontWeight:800,color:'#f59e0b',background:'rgba(245,158,11,0.12)',padding:'3px 8px',borderRadius:6}}>{availablePositions[0]}</span>
        ):availablePositions.length>1?(
          <span style={{fontSize:10,color:'#64748b'}}>{availablePositions.join('/')}</span>
        ):(
          <span style={{fontSize:10,color:'#334155'}}>—</span>
        )}
      </td>

      {/* Salary price */}
      {salaryMode&&(
        <td style={{padding:'10px 8px',textAlign:'center'}}>
          <span style={{fontSize:12,fontWeight:800,color:affordable?'#eab308':'#ef4444'}}>${price}</span>
        </td>
      )}

      {/* Stat columns */}
      {mode==='blind'?(
        <td colSpan={cols.length} style={{padding:'10px 8px',color:'#7c3aed',fontSize:11,fontStyle:'italic'}}>Stats hidden</td>
      ):(
        cols.map(c=>(
          <td key={c.k} style={{padding:'10px 8px',textAlign:'right',fontVariantNumeric:'tabular-nums'}}>
            <span style={hi(c.v,c.good)}>{c.v}</span>
          </td>
        ))
      )}

      {/* Pick button — only shown when multiple positions to choose */}
      <td style={{padding:'10px 8px',textAlign:'center'}}>
        {canPick&&availablePositions.length>1&&(
          <button
            onClick={e=>{e.preventDefault();setExpanded(ex=>!ex);}}
            onTouchEnd={e=>{e.preventDefault();setExpanded(ex=>!ex);}}
            style={{background:'linear-gradient(135deg,#f59e0b,#d97706)',color:'#000',border:'none',borderRadius:7,padding:'5px 14px',fontWeight:800,fontSize:12,cursor:'pointer',whiteSpace:'nowrap'}}>
            PICK
          </button>
        )}
        {canPick&&availablePositions.length===1&&(
          <button
            onClick={e=>{e.preventDefault();setExpanded(ex=>!ex);}}
            onTouchEnd={e=>{e.preventDefault();setExpanded(ex=>!ex);}}
            style={{background:'linear-gradient(135deg,#f59e0b,#d97706)',color:'#000',border:'none',borderRadius:7,padding:'5px 14px',fontWeight:800,fontSize:12,cursor:'pointer',whiteSpace:'nowrap'}}>
            PICK
          </button>
        )}
      </td>
    </tr>
  );
}

// ═══════════════════════════════════════════════════════════════
// ROSTER SIDEBAR
// ═══════════════════════════════════════════════════════════════
function RosterSidebar({roster,salaryMode,budgetSpent,budgetLeft}){
  const hitters=Object.values(roster).filter(p=>p&&p.type==='hitter');
  const starters=Object.values(roster).filter(p=>p&&p.role==='SP');
  const relievers=Object.values(roster).filter(p=>p&&p.role==='RP');
  const allPos=['C','1B','2B','3B','SS','LF','CF','RF','DH'];
  const filled=new Set(hitters.map(p=>p.assignedPos));
  const decades=[...new Set(Object.values(roster).filter(Boolean).map(p=>p.decade))];
  const total=Object.values(roster).filter(Boolean).length;
  const pct=salaryMode?Math.min(100,(budgetSpent/SALARY_CAP_BUDGET)*100):0;

  return(
    <div style={{width:200,minWidth:200,background:'rgba(4,10,20,0.95)',borderRight:'1px solid #0a1828',padding:'14px 10px',overflowY:'auto',fontSize:12}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:10}}>
        <span style={{fontSize:9,letterSpacing:2,color:'#334155',fontWeight:700}}>ROSTER</span>
        <span style={{fontSize:11,color:'#f59e0b',fontWeight:700}}>{total}/18</span>
      </div>
      {salaryMode&&(
        <div style={{marginBottom:12,background:'rgba(234,179,8,0.05)',border:'1px solid rgba(234,179,8,0.2)',borderRadius:8,padding:'8px 9px'}}>
          <div style={{display:'flex',justifyContent:'space-between',marginBottom:5}}>
            <span style={{fontSize:9,color:'#a16207',letterSpacing:1,fontWeight:700}}>BUDGET</span>
            <span style={{fontSize:11,fontWeight:800,color:budgetLeft<0?'#ef4444':'#eab308'}}>${budgetLeft}</span>
          </div>
          <div style={{height:5,background:'#0a1828',borderRadius:3,overflow:'hidden'}}>
            <div style={{height:'100%',width:`${pct}%`,background:budgetLeft<0?'#dc2626':'linear-gradient(90deg,#eab308,#facc15)',transition:'width .3s'}}/>
          </div>
          <div style={{fontSize:9,color:'#64748b',marginTop:4}}>${budgetSpent} of ${SALARY_CAP_BUDGET} spent</div>
        </div>
      )}
      {decades.length>0&&<div style={{display:'flex',flexWrap:'wrap',gap:3,marginBottom:10}}>
        {decades.map(d=><span key={d} style={{fontSize:9,background:'rgba(245,158,11,0.07)',border:'1px solid rgba(245,158,11,0.15)',color:'#fcd34d',padding:'2px 5px',borderRadius:3}}>{d}</span>)}
      </div>}
      <div style={{fontSize:9,letterSpacing:2,color:'#1e3a5f',fontWeight:700,marginBottom:6}}>LINEUP</div>
      {allPos.map(pos=>{
        const player=hitters.find(p=>p.assignedPos===pos);
        return(
          <div key={pos} style={{display:'flex',alignItems:'center',gap:5,padding:'4px 5px',marginBottom:2,borderRadius:5,background:player?'rgba(245,158,11,0.04)':'transparent'}}>
            <span style={{width:24,fontSize:10,color:'#3b82f6',fontWeight:700,flexShrink:0}}>{pos}</span>
            <span style={{flex:1,fontSize:11,color:player?'#e2e8f0':'#1e3a5f',fontStyle:player?'normal':'italic',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{player?player.name:'empty'}</span>
            {player&&salaryMode&&<span style={{fontSize:9,color:'#a16207',flexShrink:0,fontWeight:700}}>${playerPrice(player)}</span>}
            {player&&!salaryMode&&<span style={{fontSize:9,color:'#334155',flexShrink:0}}>{player.decade}</span>}
          </div>
        );
      })}
      <div style={{fontSize:9,letterSpacing:2,color:'#1e3a5f',fontWeight:700,marginTop:10,marginBottom:6}}>PITCHING</div>
      {Array.from({length:5},(_,i)=>{
        const sp=starters[i];
        return(
          <div key={i} style={{display:'flex',alignItems:'center',gap:5,padding:'4px 5px',marginBottom:2,borderRadius:5}}>
            <span style={{width:24,fontSize:10,color:'#60a5fa',fontWeight:700,flexShrink:0}}>SP{i+1}</span>
            <span style={{flex:1,fontSize:11,color:sp?'#e2e8f0':'#1e3a5f',fontStyle:sp?'normal':'italic',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{sp?sp.name:'empty'}</span>
            {sp&&salaryMode&&<span style={{fontSize:9,color:'#a16207',flexShrink:0,fontWeight:700}}>${playerPrice(sp)}</span>}
          </div>
        );
      })}
      {Array.from({length:4},(_,i)=>{
        const rp=relievers[i];
        return(
          <div key={i} style={{display:'flex',alignItems:'center',gap:5,padding:'4px 5px',marginBottom:2,borderRadius:5}}>
            <span style={{width:24,fontSize:10,color:'#a78bfa',fontWeight:700,flexShrink:0}}>RP{i+1}</span>
            <span style={{flex:1,fontSize:11,color:rp?'#e2e8f0':'#1e3a5f',fontStyle:rp?'normal':'italic',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{rp?rp.name:'empty'}</span>
            {rp&&salaryMode&&<span style={{fontSize:9,color:'#a16207',flexShrink:0,fontWeight:700}}>${playerPrice(rp)}</span>}
          </div>
        );
      })}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════
// LINEUP BUILDER
// ═══════════════════════════════════════════════════════════════
function LineupBuilder({roster,lineup,onLineupChange,rpRoles,onRpRolesChange,onSimulate}){
  const hitters=Object.values(roster).filter(p=>p&&p.type==='hitter');
  const starters=Object.values(roster).filter(p=>p&&p.role==='SP');
  const relievers=Object.values(roster).filter(p=>p&&p.role==='RP');
  const feedback=getLineupFeedback(lineup);
  const [drag,setDrag]=useState(null);
  const inLineup=new Set(lineup.filter(Boolean).map(p=>p?.id));
  const inLineupNames=new Set(lineup.filter(Boolean).map(p=>(p?.displayName||p?.name||'').replace(/ \([0-9]-yr\)$/,'')));
  const lineupFull=lineup.filter(Boolean).length===9;

  function handleDrop(toIdx){
    if(drag===null)return;
    const nl=[...lineup];[nl[toIdx],nl[drag]]=[nl[drag],nl[toIdx]];
    onLineupChange(nl);setDrag(null);
  }
  function addPlayer(p){const dn=(p.displayName||p.name).replace(/ ([0-9]-yr)$/,'');if(inLineupNames.has(dn))return;const nl=[...lineup];const i=nl.findIndex(x=>!x);if(i>=0){nl[i]=p;onLineupChange(nl);}}
  function remove(idx){const nl=[...lineup];nl[idx]=null;onLineupChange(nl);}

  return(
    <div style={{flex:1,overflowY:'auto',padding:'20px 24px'}}>
      <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(280px,1fr))',gap:20,maxWidth:1050}}>
        {/* Batting Order */}
        <div>
          <div style={S.sh}>BATTING ORDER</div>
          <div style={{fontSize:11,color:'#334155',marginBottom:10,fontStyle:'italic'}}>Drag to reorder · use arrows to adjust order</div>
          {BATTING_ORDER_ROLES.map((role,i)=>{
            const p=lineup[i];
            return(
              <div key={role.spot} onDragOver={e=>e.preventDefault()} onDrop={()=>handleDrop(i)}
                style={{display:'flex',alignItems:'center',gap:8,background:'rgba(8,16,32,0.7)',border:`1px solid ${p?role.color:'#0f1f35'}`,borderRadius:10,padding:'8px 10px',marginBottom:6,minHeight:46}}>
                <span style={{fontSize:16,fontWeight:900,color:role.color,width:20,textAlign:'center',flexShrink:0}}>{role.spot}</span>
                {p?(
                  <div draggable onDragStart={()=>setDrag(i)} style={{flex:1,display:'flex',alignItems:'center',gap:6,cursor:'grab'}}>
                    <span style={{flex:1,fontSize:13,fontWeight:600,overflow:'hidden',whiteSpace:'nowrap',textOverflow:'ellipsis'}}>{p.name}</span>
                    <span style={{fontSize:10,color:'#475569',flexShrink:0}}>{p.assignedPos}</span>
                    <span style={{fontSize:10,color:'#64748b',flexShrink:0}}>.{String(Math.round((p.stats?.obp||0)*1000)).padStart(3,'0')}</span>
                    <div style={{display:'flex',flexDirection:'column',gap:1,flexShrink:0}}>
                      <button onClick={e=>{e.stopPropagation();if(i===0)return;const nl=[...lineup];[nl[i],nl[i-1]]=[nl[i-1],nl[i]];onLineupChange(nl);}}
                        disabled={i===0}
                        style={{background:'none',border:'none',color:i===0?'#1e3a5f':'#475569',cursor:i===0?'default':'pointer',padding:'0 2px',fontSize:10,lineHeight:1}}>▲</button>
                      <button onClick={e=>{e.stopPropagation();if(i===lineup.length-1||!lineup[i+1]&&i>=lineup.filter(Boolean).length-1)return;const nl=[...lineup];[nl[i],nl[i+1]]=[nl[i+1],nl[i]];onLineupChange(nl);}}
                        disabled={i>=lineup.filter(Boolean).length-1}
                        style={{background:'none',border:'none',color:i>=lineup.filter(Boolean).length-1?'#1e3a5f':'#475569',cursor:i>=lineup.filter(Boolean).length-1?'default':'pointer',padding:'0 2px',fontSize:10,lineHeight:1}}>▼</button>
                    </div>

                  </div>
                ):(
                  <div style={{flex:1,fontSize:11,color:'#1e3a5f'}}>{role.hint}</div>
                )}
              </div>
            );
          })}
        </div>

        {/* Pitching */}
        <div>
          <div style={S.sh}>ROTATION ORDER</div>
          <div style={{fontSize:11,color:'#334155',marginBottom:10,fontStyle:'italic'}}>SP1 starts most games</div>
          {starters.map((sp,i)=>(
            <div key={i} style={{display:'flex',alignItems:'center',gap:8,background:'rgba(8,16,32,0.7)',border:'1px solid #0f1f35',borderRadius:10,padding:'8px 10px',marginBottom:6}}>
              <span style={{fontSize:13,fontWeight:700,color:'#60a5fa',width:28,flexShrink:0}}>SP{i+1}</span>
              <span style={{flex:1,fontSize:13,fontWeight:600,overflow:'hidden',whiteSpace:'nowrap',textOverflow:'ellipsis'}}>{sp.name}</span>
              <span style={{fontSize:10,color:'#475569',flexShrink:0}}>{sp.decade}</span>
              <span style={{fontSize:10,color:'#94a3b8',flexShrink:0}}>{sp.stats?.era} ERA</span>
            </div>
          ))}
          <div style={{...S.sh,marginTop:18}}>BULLPEN ROLES</div>
          <div style={{fontSize:11,color:'#334155',marginBottom:10,fontStyle:'italic'}}>Assign roles to relievers</div>
          {relievers.map((rp,i)=>(
            <div key={i} style={{display:'flex',alignItems:'center',gap:8,background:'rgba(8,16,32,0.7)',border:'1px solid #0f1f35',borderRadius:10,padding:'8px 10px',marginBottom:6}}>
              <select value={rpRoles[i]||''} onChange={e=>{const r=[...rpRoles];r[i]=e.target.value;onRpRolesChange(r);}}
                style={{background:'#060e1c',border:'1px solid #1e293b',color:'#94a3b8',borderRadius:6,padding:'4px 6px',fontSize:11,width:120,flexShrink:0,cursor:'pointer'}}>
                <option value="">— Role —</option>
                {RP_ROLE_OPTIONS.map(r=>{
                  const countUsed=rpRoles.filter((role,j)=>j!==i&&role===r.id).length;
                  const limit=r.id==='cl'?1:2;
                  const disabled=countUsed>=limit;
                  return <option key={r.id} value={r.id} disabled={disabled} style={{color:disabled?'#334155':'inherit'}}>{r.label}{disabled?' (full)':countUsed>0?` (${limit-countUsed} left)`:''}</option>;
                })}
              </select>
              <span style={{flex:1,fontSize:13,fontWeight:600,overflow:'hidden',whiteSpace:'nowrap',textOverflow:'ellipsis'}}>{rp.name}</span>
              <span style={{fontSize:10,color:'#94a3b8',flexShrink:0}}>{rp.stats?.era} ERA</span>
            </div>
          ))}
        </div>

        {/* Simulate button */}
        <div>
          <button onClick={onSimulate} disabled={!lineupFull}
            style={{width:'100%',marginTop:8,background:lineupFull?'linear-gradient(135deg,#f59e0b,#d97706)':'#0f1f35',color:lineupFull?'#000':'#334155',border:'none',borderRadius:12,padding:'16px',fontWeight:900,fontSize:15,cursor:lineupFull?'pointer':'not-allowed',letterSpacing:1}}>
            {lineupFull?'⚡ SIMULATE 162 GAMES':'Fill all 9 batting spots first'}
          </button>
        </div>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════
// RESULTS
// ═══════════════════════════════════════════════════════════════
function ResultsScreen({result,onReset,onShare}){
  const [anim,setAnim]=useState(0);const[show,setShow]=useState(false);
  useEffect(()=>{
    let n=0;const t=result.wins;
    // Slower animation: ~3 seconds for dramatic effect
    const duration=3000, steps=90, inc=t/steps;
    const iv=setInterval(()=>{n=Math.min(n+inc,t);setAnim(Math.round(n));if(n>=t){clearInterval(iv);setTimeout(()=>setShow(true),600);}},duration/steps);
    return()=>clearInterval(iv);
  },[result.wins]);
  const col=result.wins>=116?'#FFD700':result.wins>=100?'#60a5fa':result.wins>=90?'#4ade80':result.wins>=81?'#94a3b8':'#f87171';
  return(
    <div style={{minHeight:'100vh',background:'radial-gradient(ellipse at 50% 0%,#0d2137,#060c14 70%)',display:'flex',alignItems:'center',justifyContent:'center',padding:20,fontFamily:'Georgia,serif',color:'#e2e8f0'}}>
      <div style={{background:'rgba(6,14,28,0.98)',border:'1px solid #1e3a5f',borderRadius:28,padding:'48px 56px',maxWidth:500,width:'100%',textAlign:'center'}}>
        <div style={{fontSize:10,letterSpacing:6,color:'#334155',marginBottom:32}}>SEASON COMPLETE</div>
        <div style={{display:'flex',alignItems:'baseline',justifyContent:'center',gap:10,marginBottom:14}}>
          <span style={{fontSize:96,fontWeight:900,color:col,lineHeight:1,fontFamily:'Georgia,serif'}}>{anim}</span>
          <span style={{fontSize:48,color:'#1e3a5f'}}>-</span>
          <span style={{fontSize:64,fontWeight:700,color:'#1e3a5f',fontFamily:'Georgia,serif'}}>{162-anim}</span>
        </div>
        
        {show&&(
          <div style={{textAlign:'left',marginBottom:32}}>
            {[
              ['Runs Scored / G', result.rpg],
              ['Runs Allowed / G', result.rapg],
              ['Run Differential', `${result.rpg-result.rapg>=0?'+':''}${Math.round((result.rpg-result.rapg)*10)/10} / game`],
              ['Team wRC+', `${result.avgWRC} (${result.avgWRC>=100?'+':''}${result.avgWRC-100}% offense)`],
              ['Win Probability', `${Math.round(result.winPct*1000)/10}%`],
              ['Lineup Construction', `${result.constructionPct>=0?'+':''}${(result.constructionPct*100).toFixed(1)}% runs`],
              ...(result.decadeMode ? [] : [['Era Diversity', result.era?.label]]),
            ].map(([l,v])=>(
              <div key={l} style={{display:'flex',justifyContent:'space-between',padding:'7px 0',borderBottom:'1px solid #0a1828',fontSize:13,gap:12}}>
                <span style={{color:'#475569',flexShrink:0}}>{l}</span><span style={{color:'#e2e8f0',fontWeight:600,textAlign:'right'}}>{v}</span>
              </div>
            ))}

            {result.salaryMode&&(
              <div style={{marginTop:16,background:'rgba(234,179,8,0.05)',border:'1px solid rgba(234,179,8,0.2)',borderRadius:10,padding:'12px 14px'}}>
                <div style={{fontSize:9,letterSpacing:2,color:'#a16207',marginBottom:8,fontWeight:700}}>💰 SALARY CAP RESULT</div>
                {[
                  ['Budget Spent', `$${result.budgetSpent} of $${result.budgetTotal}`],
                  ['Budget Remaining', `$${result.budgetTotal-result.budgetSpent}`],
                  ['Value', `${(result.wins/result.budgetSpent*100).toFixed(1)} wins per $100`],
                ].map(([l,v])=>(
                  <div key={l} style={{display:'flex',justifyContent:'space-between',fontSize:12,padding:'3px 0',color:'#a16207',gap:12}}>
                    <span style={{opacity:0.8}}>{l}</span><span style={{fontWeight:700,color:'#eab308'}}>{v}</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
        <div style={{display:'flex',gap:10}}>
          <button onClick={onReset} style={{flex:1,background:'linear-gradient(135deg,#f59e0b,#d97706)',color:'#000',border:'none',borderRadius:12,padding:'14px 8px',fontWeight:900,fontSize:14,cursor:'pointer',letterSpacing:0,whiteSpace:'nowrap'}}>DRAFT AGAIN</button>
          <button onClick={onShare} style={{flex:1,background:'rgba(96,165,250,0.08)',border:'1px solid #3b82f6',color:'#93c5fd',borderRadius:12,padding:'15px',fontWeight:700,fontSize:13,cursor:'pointer'}}>📋 Copy</button>
        </div>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════
// DATA LOADER
// ═══════════════════════════════════════════════════════════════
function DataLoader({onLoaded}){
  const [files,setFiles]=useState([]);const[busy,setBusy]=useState(false);const[err,setErr]=useState('');
  function handleFiles(e){
    const nf=Array.from(e.target.files).map(f=>({file:f,name:f.name,type:/pitch/i.test(f.name)?'pitcher':'hitter',decade:DECADES.find(d=>f.name.includes(d.replace('s','')))||''}));
    setFiles(p=>[...p,...nf]);
  }
  async function process(){
    setBusy(true);setErr('');
    try{
      const cf=[];for(const f of files){const c=await f.file.text();cf.push({...f,content:c});}
      const players=processCSVFiles(cf);
      if(!players.length){setErr('No valid data found. Check CSV format.');setBusy(false);return;}
      onLoaded(players);
    }catch(e){setErr('Error: '+e.message);setBusy(false);}
  }
  return(
    <div style={{minHeight:'100vh',background:'radial-gradient(ellipse at top,#0d2137,#060c14)',display:'flex',alignItems:'center',justifyContent:'center',padding:20,fontFamily:'Georgia,serif',color:'#e2e8f0'}}>
      <div style={{background:'rgba(6,14,28,0.98)',border:'1px solid #1e3a5f',borderRadius:24,padding:'44px 48px',maxWidth:540,width:'100%',textAlign:'center'}}>
        <div style={{fontSize:28,fontWeight:900,color:'#f59e0b',marginBottom:6,letterSpacing:-1}}>LOAD YOUR DATA</div>
        <div style={{fontSize:13,color:'#475569',marginBottom:28}}>Upload Fangraphs CSV exports — 16 files total (8 hitting + 8 pitching by decade)</div>
        <input type="file" accept=".csv" multiple onChange={handleFiles} style={{display:'none'}} id="fu"/>
        <label htmlFor="fu" style={{display:'inline-block',background:'rgba(245,158,11,0.07)',border:'2px dashed #d97706',color:'#f59e0b',borderRadius:12,padding:'18px 36px',cursor:'pointer',fontSize:14,fontWeight:700,marginBottom:12}}>📂 Select CSV Files</label>
        <div style={{fontSize:11,color:'#334155',marginBottom:16}}>Name files: <code style={{color:'#64748b'}}>hitters_1960s.csv</code> / <code style={{color:'#64748b'}}>pitchers_1980s.csv</code></div>
        {files.length>0&&<>
          <div style={{background:'rgba(6,12,24,0.9)',border:'1px solid #0a1828',borderRadius:10,padding:10,maxHeight:160,overflowY:'auto',textAlign:'left',marginBottom:14}}>
            {files.map((f,i)=><div key={i} style={{display:'flex',justifyContent:'space-between',padding:'3px 0',fontSize:11,color:'#64748b',borderBottom:'1px solid #060e1c'}}><span>{f.type==='hitter'?'🏏':'⚾'} {f.name}</span><span style={{color:'#334155'}}>{f.decade||'?'}</span></div>)}
          </div>
          {err&&<div style={{color:'#f87171',fontSize:12,marginBottom:10}}>{err}</div>}
          <button onClick={process} disabled={busy} style={{width:'100%',background:busy?'#0f1f35':'linear-gradient(135deg,#f59e0b,#d97706)',color:busy?'#334155':'#000',border:'none',borderRadius:12,padding:'14px',fontWeight:900,fontSize:14,cursor:busy?'default':'pointer',marginBottom:10}}>
            {busy?'Processing...':'Process & Start Game'}
          </button>
        </>}
        <button onClick={()=>onLoaded(null)} style={{width:'100%',background:'transparent',border:'1px solid #0f1f35',color:'#334155',borderRadius:10,padding:'11px',cursor:'pointer',fontSize:12}}>▶ Continue with Sample Players</button>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════
// SHARED STYLES
// ═══════════════════════════════════════════════════════════════
const S={sh:{fontSize:9,letterSpacing:3,color:'#334155',fontWeight:700,marginBottom:8}};

// ═══════════════════════════════════════════════════════════════
// MAIN APP
// ═══════════════════════════════════════════════════════════════
export default function App(){
  const [screen,setScreen]=useState('home');
  const [mode,setMode]=useState('classic');
  const [isDaily,setIsDaily]=useState(false);
  const [players,setPlayers]=useState(SAMPLE_PLAYERS);
  const [roster,setRoster]=useState({});
  const [spinning,setSpinning]=useState(false);
  const [spinRes,setSpinRes]=useState(null);
  const [pool,setPool]=useState([]);
  const [lineup,setLineup]=useState(Array(9).fill(null));
  const [rpRoles,setRpRoles]=useState(['CL','SU','LR','LS']);
  const [result,setResult]=useState(null);
  const [dailyRolls,setDailyRolls]=useState([]);
  const [dailyIdx,setDailyIdx]=useState(0);
  const [roundNum,setRoundNum]=useState(1);
  const [salaryMode,setSalaryMode]=useState(false);
  const [teamRerolls,setTeamRerolls]=useState(0);    // how many times team has been rerolled
  const [decadeRerolls,setDecadeRerolls]=useState(0); // how many times decade has been rerolled
  const [lockedDecade,setLockedDecade]=useState(null); // for Decades mode — null until first spin locks it
  const [decadeMode,setDecadeMode]=useState(false);
  const [rerollMode,setRerollMode]=useState(null); // 'team' or 'decade' during reroll animation
  const [showRoster,setShowRoster]=useState(false); // mobile: toggle roster sidebar

  const filled=Object.values(roster).filter(Boolean).length;
  const needed=getNeededPositions(roster);
  const draftComplete=filled===18;
  // Salary cap accounting
  const budgetSpent=Object.values(roster).filter(Boolean).reduce((s,p)=>s+playerPrice(p),0);
  const budgetLeft=SALARY_CAP_BUDGET-budgetSpent;
  const slotsLeft=18-filled;

  function startGame(m,daily=false,salary=false,decMode=false){
    setMode(m);setIsDaily(daily);setSalaryMode(salary);setDecadeMode(decMode);setLockedDecade(null);
    setRoster({});setSpinRes(null);setPool([]);
    setLineup(Array(9).fill(null));setRpRoles(['CL','SU','LR','LS']);setResult(null);setRoundNum(1);
    setTeamRerolls(0);setDecadeRerolls(0);
    if(daily){
      let s=todaySeed();const rng=()=>{s=(s*9301+49297)%233280;return s/233280;};
      setDailyRolls(Array.from({length:60},()=>{const dec=DECADES[Math.floor(rng()*DECADES.length)];return{team:TEAMS_BY_DECADE[dec][Math.floor(rng()*TEAMS_BY_DECADE[dec].length)],decade:dec};}));
      setDailyIdx(0);
    }
    setScreen('draft');
  }

  function spin(){
    if(spinning)return;
    setSpinning(true);setPool([]);
    setTimeout(()=>{
      let res;
      if(decadeMode && !lockedDecade){
        // FIRST spin in decade mode: pick a decade only, no team yet
        const dec=DECADES[Math.floor(Math.random()*DECADES.length)];
        setLockedDecade(dec);
        setSpinRes({team:null,decade:dec});
        setSpinning(false);
        setPool([]); // no pool yet — user must spin for a team
        return;
      }
      // Exclude by both ID and display name — no drafting Barry Bonds twice
      const draftedIds=new Set(Object.values(roster).filter(Boolean).map(p=>p.id));
      const draftedNames=new Set(Object.values(roster).filter(Boolean).map(p=>(p.displayName||p.name||'').replace(/ \d-yr$/,'')));
      const notDrafted=p=>{ if(draftedIds.has(p.id)) return false; const dn=(p.displayName||p.name).replace(/ ([0-9]-yr)$/,''); return !draftedNames.has(dn); };

      // What positions do we still need?
      const neededNow=getNeededPositions(roster);
      const needsH=neededNow.hitter.length>0;
      const needsSP=neededNow.sp>0;
      const needsRP=neededNow.rp>0;

      // Check if a team+decade combo has any player matching current needs
      function poolHasNeeded(team, decade) {
        return players.some(p => {
          if (!notDrafted(p) || p.team!==team || p.decade!==decade) return false;
          if (p.type==='pitcher') {
            if (p.role==='SP' && needsSP) return true;
            if (p.role==='RP' && needsRP) return true;
            return false;
          }
          // hitter: check eligible positions against needed hitter slots
          return needsH && p.eligiblePositions.some(pos=>neededNow.hitter.includes(pos));
        });
      }

      // Normal spin or decade mode subsequent spins (team only, decade locked)
      // Re-roll up to 50 times to find a team with eligible players for current needs
      let attempts=0;
      if(isDaily&&dailyRolls.length>0){
        res=dailyRolls[dailyIdx]||randTeamDecade();setDailyIdx(i=>i+1);
      } else {
        do {
          if(decadeMode && lockedDecade){
            const teams=TEAMS_BY_DECADE[lockedDecade]||[];
            const team=teams[Math.floor(Math.random()*teams.length)];
            res={team,decade:lockedDecade};
          } else {
            res=randTeamDecade();
          }
          attempts++;
        } while(attempts<50 && !poolHasNeeded(res.team, res.decade));
      }

      setSpinRes(res);setSpinning(false);setRerollMode(null);

      // STRICT filtering: only players who actually played for that team in that decade
      const strictPool=players.filter(p=>
        notDrafted(p) &&
        p.team===res.team &&
        p.decade===res.decade
      ).sort((a,b)=>(b.avgWARperYear||0)-(a.avgWARperYear||0));

      // Fallback: same decade, any team — but NEVER show players from wrong decade
      const decadePool=strictPool.length>0?strictPool:players.filter(p=>
        notDrafted(p)&&p.decade===res.decade
      ).sort((a,b)=>(b.avgWARperYear||0)-(a.avgWARperYear||0)).slice(0,8);

      setPool(decadePool);
    },1600);
  }

  function pick(player) {
    // Guard against double-picking while state is updating
    const draftedNames = new Set(Object.values(roster).filter(Boolean).map(p=>(p.displayName||p.name).replace(/ ([0-9]-yr)$/,'')));
    const playerName = (player.displayName||player.name).replace(/ ([0-9]-yr)$/,'');
    if (draftedNames.has(playerName)) return;

    // Find the correct next empty slot based on player type
    let slotId;
    if (player.role === 'SP') {
      slotId = ROSTER_NEEDS.filter(s=>s.id.startsWith('sp')).find(s=>!roster[s.id])?.id;
    } else if (player.role === 'RP') {
      slotId = ROSTER_NEEDS.filter(s=>s.id.startsWith('rp')).find(s=>!roster[s.id])?.id;
    } else {
      // For hitters, find a slot matching their assigned position specifically,
      // then fall back to any empty hitter slot
      const assignedPos = (player.assignedPos||'').toLowerCase();
      const posSlot = ROSTER_NEEDS.find(s => s.id === assignedPos && !roster[s.id]);
      slotId = posSlot?.id || ROSTER_NEEDS.filter(s=>s.type==='hitter').find(s=>!roster[s.id])?.id;
    }

    if (!slotId) return;
    const newRoster = {...roster, [slotId]: player};
    setRoster(newRoster);
    setRoundNum(r => r+1);

    const newFilled = Object.values(newRoster).filter(Boolean).length;
    if (newFilled === 18) {
      // Smart lineup init: sort by OBP descending for a sensible starting order
      const h = Object.values(newRoster).filter(p=>p.type==='hitter');
      const sorted = [...h].sort((a,b) => (b.stats?.obp||0) - (a.stats?.obp||0));
      // Put highest OBP at top, highest power (SLG) in middle (spots 3-5)
      const byOBP  = [...sorted];
      const byPow  = [...h].sort((a,b) => (b.stats?.slg||0) - (a.stats?.slg||0));
      const order  = Array(9).fill(null);
      // Spots 3,4,5 get top power hitters
      [0,1,2].forEach((i,j) => { order[2+j] = byPow[i]; });
      // Remaining spots filled by OBP order
      byOBP.filter(p => !order.includes(p)).forEach((p,i) => {
        const empty = order.findIndex((x,idx) => !x && idx < 9);
        if (empty >= 0) order[empty] = p;
      });
      setLineup(order.map((p,i) => p || h[i] || null));
      setScreen('lineup');
    } else {
      setSpinRes(null); setPool([]);
    }
  }

  function runSim(){
    const r=simulate(roster,lineup,decadeMode);
    if(!r) return; // incomplete lineup guard
    if(salaryMode){ r.salaryMode=true; r.budgetSpent=budgetSpent; r.budgetTotal=SALARY_CAP_BUDGET; }
    setResult(r);setScreen('results');
  }

  function reset(){setScreen('home');setRoster({});setSpinRes(null);setPool([]);setResult(null);setRoundNum(1);setSalaryMode(false);setDecadeMode(false);setLockedDecade(null);setTeamRerolls(0);setDecadeRerolls(0);}

  const appStyle={minHeight:'100vh',background:'linear-gradient(135deg,#060c18,#0a1220)',color:'#e2e8f0',fontFamily:'Georgia,"Times New Roman",serif',display:'flex',flexDirection:'column'};
  const headerStyle={display:'flex',justifyContent:'space-between',alignItems:'center',padding:'12px 20px',background:'rgba(4,8,18,0.97)',borderBottom:'1px solid #0a1828',position:'sticky',top:0,zIndex:10};

  // HOME
  if(screen==='home') return(
    <div style={{...appStyle,alignItems:'center',justifyContent:'center',padding:20,background:'radial-gradient(ellipse at 50% -10%,#0d2848,#050c18 60%)'}}>
      <div style={{maxWidth:720,width:'100%',textAlign:'center'}}>
        <div style={{fontSize:58,fontWeight:900,color:'#f59e0b',letterSpacing:'-2px',lineHeight:1,textShadow:'0 0 80px rgba(245,158,11,0.3)',fontFamily:'Georgia,serif'}}>All-Time Draft</div>
        
        <div style={{fontSize:26,fontWeight:700,marginBottom:10,color:'#f1f5f9'}}>Can you go 162-0?</div>
        <div style={{fontSize:14,color:'#475569',marginBottom:44,lineHeight:1.7}}>Draft players. Order your lineup. Simulate a 162-game season.</div>
        <div style={{display:'flex',gap:14,justifyContent:'center',marginBottom:30,flexWrap:'wrap'}}>
          {[
            {icon:'📊',name:'Classic',desc:'Stats visible',m:'classic',daily:false,salary:false,c:'#3b82f6'},
            {icon:'🧠',name:'BlindMode',desc:'Draft from memory',m:'blind',daily:false,salary:false,c:'#8b5cf6'},
            {icon:'💰',name:'Salary Cap',desc:`$${SALARY_CAP_BUDGET} budget · spin & spend`,m:'classic',daily:false,salary:true,c:'#eab308'},
            {icon:'📅',name:'Decades',desc:'Lock an era, draft from it',m:'classic',daily:false,salary:false,decade:true,c:'#22c55e'},
          ].map(b=>(
            <div key={b.name} onClick={()=>startGame(b.m,b.daily,b.salary,!!b.decade)}
              style={{background:'rgba(8,16,32,0.8)',border:`1px solid ${b.c}18`,borderRadius:16,padding:'24px 28px',width:180,cursor:'pointer',textAlign:'center'}}
              onMouseEnter={e=>e.currentTarget.style.borderColor=b.c}
              onMouseLeave={e=>e.currentTarget.style.borderColor=b.c+'18'}>
              <div style={{fontSize:32,marginBottom:10}}>{b.icon}</div>
              <div style={{fontSize:15,fontWeight:700,marginBottom:6,color:'#f1f5f9'}}>{b.name}</div>
              <div style={{fontSize:11,color:'#475569',marginBottom:16,lineHeight:1.4}}>{b.desc}</div>
              <div style={{background:b.c,color:'#000',borderRadius:7,padding:'9px 0',fontWeight:800,fontSize:12}}>Play</div>
            </div>
          ))}
        </div>

        {/* How It Works */}
        <div style={{marginTop:40,textAlign:'left',background:'rgba(8,16,32,0.6)',border:'1px solid #0f1f35',borderRadius:16,padding:'28px 32px',maxWidth:720}}>
          <div style={{fontSize:11,letterSpacing:3,color:'#334155',fontWeight:700,marginBottom:20}}>HOW IT WORKS</div>
          <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(200px,1fr))',gap:24}}>

            <div>
              <div style={{fontSize:13,fontWeight:700,color:'#f59e0b',marginBottom:8}}>🎰 The Draft</div>
              <div style={{fontSize:12,color:'#475569',lineHeight:1.7}}>
                Spin the slot machine to land on a team and decade. You pick any player from that pool — hitters and pitchers together. 18 rounds total: 9 hitters, 5 starters, 4 relievers. Use your 2 team rerolls and 2 decade rerolls wisely.
              </div>
            </div>

            <div>
              <div style={{fontSize:13,fontWeight:700,color:'#f59e0b',marginBottom:8}}>📊 Player Value (WAR/yr)</div>
              <div style={{fontSize:12,color:'#475569',lineHeight:1.7}}>
                Each player shows their peak — their best 3-year window at that franchise. WAR/yr is the core value stat: it combines hitting, fielding, and baserunning into one number. wRC+ measures offense (100 = league average, 150 = exceptional). For pitchers, ERA and FIP drive the simulation.
              </div>
            </div>

            <div>
              <div style={{fontSize:13,fontWeight:700,color:'#f59e0b',marginBottom:8}}>📋 Batting Order Matters</div>
              <div style={{fontSize:12,color:'#475569',lineHeight:1.7}}>
                Where you slot players affects your run total. High-OBP players belong at the top — they set the table. A weak OBP bat leading off hurts you. The simulation grades your order.
              </div>
            </div>

            <div>
              <div style={{fontSize:13,fontWeight:700,color:'#f59e0b',marginBottom:8}}>⚾ The Simulation</div>
              <div style={{fontSize:12,color:'#475569',lineHeight:1.7}}>
                Your team plays a full 162-game season. Runs scored come from your lineup's wRC+. Runs allowed come from your rotation and bullpen's ERA/FIP blend. Defense (dWAR) saves real runs — elite gloves at SS, C, and CF matter most. Win probability uses the Pythagenpat formula, the most accurate baseball predictor.
              </div>
            </div>

          </div>
        </div>

      </div>
    </div>
  );

  if(screen==='results'&&result) return <ResultsScreen result={result} onReset={reset} onShare={()=>navigator.clipboard?.writeText(`All-Time Draft\n${result.wins}-${result.losses} | ${result.benchmark?.label}`).catch(()=>{})}/>;

  // LINEUP
  if(screen==='lineup') return(
    <div style={appStyle}>
      <div style={headerStyle}>
        <div style={{display:'flex',alignItems:'center',gap:12}}>
          <span style={{fontSize:18,fontWeight:900,color:'#f59e0b',letterSpacing:'-1px'}}>162-0</span>
          <span style={{fontSize:12,color:'#475569'}}>Phase 2 — Build Your Lineup</span>
        </div>
        <div style={{display:'flex',alignItems:'center',gap:10}}>
          <span style={{fontSize:11,color:'#334155'}}>Draft complete · {filled} players</span>
          <button onClick={reset} style={{fontSize:10,background:'transparent',border:'1px solid #1e293b',color:'#475569',padding:'3px 10px',borderRadius:5,cursor:'pointer'}}>✕ Quit</button>
        </div>
      </div>
      <LineupBuilder roster={roster} lineup={lineup} onLineupChange={setLineup} rpRoles={rpRoles} onRpRolesChange={setRpRoles} onSimulate={runSim}/>
    </div>
  );

  // DRAFT
  const needStr=[
    ...needed.hitter.map(p=>p),
    needed.sp>0?`${needed.sp}×SP`:'',
    needed.rp>0?`${needed.rp}×RP`:'',
  ].filter(Boolean).join(', ');

  return(
    <div style={appStyle}>
      <div style={headerStyle}>
        <div style={{display:'flex',alignItems:'center',gap:12}}>
          <span style={{fontSize:18,fontWeight:900,color:'#f59e0b',letterSpacing:'-1px'}}>162-0</span>
          <span style={{fontSize:12,color:'#475569'}}>Round {roundNum} of 18</span>
          <button onClick={()=>setShowRoster(s=>!s)} style={{fontSize:12,fontWeight:800,background:showRoster?'rgba(245,158,11,0.25)':'rgba(245,158,11,0.15)',border:'2px solid #f59e0b',color:'#f59e0b',padding:'5px 12px',borderRadius:8,cursor:'pointer',letterSpacing:0.5}}>{showRoster?'✕ ROSTER':'📋 ROSTER '+filled+'/18'}</button>
        </div>
        <div style={{display:'flex',gap:8,alignItems:'center'}}>
          {salaryMode&&<span style={{fontSize:11,background:budgetLeft<0?'rgba(239,68,68,0.15)':'rgba(234,179,8,0.12)',border:`1px solid ${budgetLeft<0?'#dc2626':'rgba(234,179,8,0.4)'}`,color:budgetLeft<0?'#ef4444':'#eab308',padding:'4px 12px',borderRadius:5,fontWeight:800}}>💰 ${budgetLeft} left</span>}
          {decadeMode&&lockedDecade&&<span style={{fontSize:11,background:'rgba(34,197,94,0.12)',border:'1px solid rgba(34,197,94,0.4)',color:'#22c55e',padding:'4px 12px',borderRadius:5,fontWeight:800}}>📅 {lockedDecade} locked</span>}
          {isDaily&&<span style={{fontSize:10,background:'rgba(34,197,94,0.08)',border:'1px solid #15803d',color:'#4ade80',padding:'3px 8px',borderRadius:5}}>📅 Daily</span>}
          <span style={{fontSize:10,background:salaryMode?'rgba(234,179,8,0.08)':'rgba(139,92,246,0.08)',border:`1px solid ${salaryMode?'rgba(234,179,8,0.3)':'#6d28d9'}`,color:salaryMode?'#eab308':'#c4b5fd',padding:'3px 8px',borderRadius:5}}>{salaryMode?'💰 Salary':mode==='blind'?'🧠 Blind':'📊 Classic'}</span>
          <span style={{fontSize:10,background:'rgba(245,158,11,0.06)',border:'1px solid rgba(245,158,11,0.2)',color:'#fcd34d',padding:'3px 8px',borderRadius:5}}>{[...new Set(Object.values(roster).filter(Boolean).map(p=>p.decade))].length} eras</span>
          <button onClick={reset} style={{fontSize:10,background:'transparent',border:'1px solid #1e293b',color:'#475569',padding:'3px 10px',borderRadius:5,cursor:'pointer'}}>✕ Quit</button>
        </div>
      </div>
      <div style={{height:2,background:'#060e1c'}}><div style={{height:'100%',background:'linear-gradient(90deg,#f59e0b,#fbbf24)',width:`${(filled/18)*100}%`,transition:'width .3s'}}/></div>

      <div style={{display:'flex',flex:1,overflow:'hidden',position:'relative'}}>
        {/* Sidebar — hidden on mobile unless toggled */}
        <div style={{display:'none'}} className="desktop-sidebar">
          <RosterSidebar roster={roster} salaryMode={salaryMode} budgetSpent={budgetSpent} budgetLeft={budgetLeft}/>
        </div>
        {/* Mobile roster overlay */}
        {showRoster&&(
          <div onClick={()=>setShowRoster(false)} style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.7)',zIndex:50,display:'flex',alignItems:'flex-end'}}>
            <div onClick={e=>e.stopPropagation()} style={{width:'100%',maxHeight:'80vh',overflowY:'auto',background:'rgba(4,10,20,0.98)',borderTop:'2px solid #1e3a5f',borderRadius:'16px 16px 0 0'}}>
              <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',padding:'12px 16px',borderBottom:'1px solid #0f1f35'}}>
                <span style={{fontSize:11,letterSpacing:2,color:'#334155',fontWeight:700}}>ROSTER {filled}/18</span>
                <button onClick={()=>setShowRoster(false)} style={{background:'none',border:'none',color:'#475569',fontSize:18,cursor:'pointer'}}>✕</button>
              </div>
              <RosterSidebar roster={roster} salaryMode={salaryMode} budgetSpent={budgetSpent} budgetLeft={budgetLeft}/>
            </div>
          </div>
        )}
        <div style={{flex:1,padding:'12px 16px',overflowY:'auto',display:'flex',flexDirection:'column',alignItems:'center'}}>

          {/* Still needed */}
          {needStr&&<div style={{fontSize:11,color:'#475569',marginBottom:16,background:'rgba(8,16,32,0.6)',padding:'7px 16px',borderRadius:16,border:'1px solid #0f1f35'}}>
            Still need: <span style={{color:'#f59e0b',fontWeight:600}}>{needStr}</span>
          </div>}

          {!(decadeMode&&spinRes&&!spinRes.team)&&<SlotMachine spinning={spinning} result={spinRes} decadeMode={decadeMode} lockedDecade={lockedDecade} rerollMode={rerollMode}/>}

          {!spinRes&&!spinning&&(
            <div style={{textAlign:'center'}}>
              {decadeMode&&!lockedDecade&&<div style={{fontSize:13,color:'#22c55e',marginBottom:12,fontWeight:600}}>Spin to lock your decade — you'll draft from it all game</div>}
              <button onClick={spin} style={{marginTop:4,background:'linear-gradient(135deg,#f59e0b,#d97706)',color:'#000',border:'none',borderRadius:12,padding:'16px 52px',fontWeight:900,fontSize:18,cursor:'pointer',letterSpacing:2}}>
                {decadeMode&&!lockedDecade?'🎲 SPIN YOUR DECADE':'🎰 SPIN'}
              </button>
            </div>
          )}

          {spinRes&&!spinning&&pool.length===0&&(
            <div style={{textAlign:'center',color:'#334155',marginTop:20}}>
              {decadeMode&&!spinRes.team?(
                <>
                  <div style={{fontSize:28,fontWeight:900,color:'#22c55e',marginBottom:8,letterSpacing:1}}>{spinRes.decade}</div>
                  <div style={{fontSize:13,color:'#475569',marginBottom:20}}>Your decade is locked. Now spin to get a team.</div>
                  <button onClick={spin} style={{background:'linear-gradient(135deg,#22c55e,#16a34a)',color:'#000',border:'none',borderRadius:12,padding:'14px 40px',fontWeight:900,fontSize:16,cursor:'pointer',letterSpacing:1}}>🎰 SPIN FOR A TEAM</button>
                </>
              ):(
                <>
                  <div style={{marginBottom:10,fontSize:13}}>No players found for <strong style={{color:'#f59e0b'}}>{spinRes.team}</strong> in the <strong style={{color:'#60a5fa'}}>{spinRes.decade}</strong>.</div>
                  <button onClick={spin} style={{background:'rgba(245,158,11,0.08)',border:'1px solid #d97706',color:'#f59e0b',borderRadius:8,padding:'10px 24px',cursor:'pointer',fontWeight:700,fontSize:13}}>🎰 Spin Again</button>
                </>
              )}
            </div>
          )}

          {pool.length>0&&(
            <>
              {pool.every(p=>p.team!==spinRes?.team)&&(
                <div style={{fontSize:11,color:'#475569',marginBottom:10,fontStyle:'italic'}}>No {spinRes?.team} players available — showing best from the {spinRes?.decade}</div>
              )}
              <div style={{width:'100%',maxWidth:1000,marginTop:12,overflowX:'auto',WebkitOverflowScrolling:'touch'}}>
                {(()=>{
                  const hitters=pool.filter(p=>p.type==='hitter').sort((a,b)=>(b.avgWARperYear||0)-(a.avgWARperYear||0));
                  const pitchers=pool.filter(p=>p.type==='pitcher').sort((a,b)=>(b.avgWARperYear||0)-(a.avgWARperYear||0));
                  const hHeaders=['WAR/yr','AVG','OBP','SLG','HR','wRC+','BsR','dWAR'];
                  const pHeaders=['WAR/yr','ERA','FIP','WHIP','K/9','IP'];
                  const thStyle={padding:'6px 8px',textAlign:'right',fontSize:9,letterSpacing:1,color:'#334155',fontWeight:700};
                  const isMobile=window.innerWidth<700;
                  const mobileHHdrs=['WAR/yr','OBP','HR'];
                  const mobilePHdrs=['WAR/yr','ERA','FIP'];
                  const secHead=(label,headers)=>{
                    const hdrs=isMobile?(label==='BATTERS'?mobileHHdrs:mobilePHdrs):headers;
                    return(
                    <tr style={{borderBottom:'2px solid #1e3a5f',borderTop:'1px solid #0a1828'}}>
                      <th style={{padding:'8px 12px',textAlign:'left',fontSize:9,letterSpacing:2,color:'#475569',fontWeight:700}}>{label}</th>
                      <th style={{padding:'6px 8px',textAlign:'center',fontSize:9,letterSpacing:2,color:'#334155',fontWeight:700}}>POS</th>
                      {salaryMode&&<th style={{padding:'6px 8px',textAlign:'center',fontSize:9,letterSpacing:2,color:'#a16207',fontWeight:700}}>$</th>}
                      {mode!=='blind'&&hdrs.map(h=>(
                        <th key={h} style={thStyle}>{h}</th>
                      ))}
                      <th style={{padding:'6px 8px',width:60}}></th>
                    </tr>
                  );};
                  const cardProps={mode,onPick:pick,filledPositions:getFilledPositions(roster),neededPositions:needed,salaryMode,budgetLeft,slotsLeft,players,roster,isMobile};
                  return(
                    <table style={{width:'100%',borderCollapse:'collapse',fontSize:12}}>
                      {hitters.length>0&&<>
                        <thead>{secHead('BATTERS',hHeaders)}</thead>
                        <tbody>{hitters.map(p=><PlayerCard key={p.id} player={p} {...cardProps}/>)}</tbody>
                      </>}
                      {pitchers.length>0&&<>
                        <thead>{secHead('PITCHERS',pHeaders)}</thead>
                        <tbody>{pitchers.map(p=><PlayerCard key={p.id} player={p} {...cardProps}/>)}</tbody>
                      </>}
                    </table>
                  );
                })()}
              </div>
              {/* Reroll buttons — 2 team rerolls + 2 decade rerolls per round */}
              <div style={{display:'flex',gap:8,marginTop:12,flexWrap:'wrap',justifyContent:'center',width:'100%',maxWidth:500}}>
                <button
                  disabled={teamRerolls>=2}
                  onClick={()=>{
                    if(teamRerolls>=2) return;
                    const dec=lockedDecade||spinRes.decade;
                    // Pick the best team upfront before spinning
                    const draftedIds=new Set(Object.values(roster).filter(Boolean).map(p=>p.id));
                    const draftedNames=new Set(Object.values(roster).filter(Boolean).map(p=>(p.displayName||p.name||'').replace(/ \d-yr$/,'')));
                    const notDrafted=p=>{if(draftedIds.has(p.id))return false;const dn=(p.displayName||p.name||'').replace(/ \d-yr$/,'');return !draftedNames.has(dn);};
                    const neededNow2=getNeededPositions(roster);
                    const otherTeams=(TEAMS_BY_DECADE[dec]||[]).filter(t=>t!==spinRes.team);
                    const eligible2=otherTeams.filter(t=>players.some(p=>notDrafted(p)&&p.team===t&&p.decade===dec));
                    const pool2=eligible2.length>0?eligible2:otherTeams;
                    const finalTeam=pool2[Math.floor(Math.random()*pool2.length)]||spinRes.team;
                    const finalRes={team:finalTeam,decade:dec};
                    setTeamRerolls(r=>r+1);
                    setPool([]);setRerollMode('team');
                    setSpinning(true);
                    setTimeout(()=>{
                      setSpinRes(finalRes);setSpinning(false);setRerollMode(null);
                      const strict=players.filter(p=>notDrafted(p)&&p.team===finalTeam&&p.decade===dec).sort((a,b)=>(b.avgWARperYear||0)-(a.avgWARperYear||0));
                      const fallback=strict.length>0?strict:players.filter(p=>notDrafted(p)&&p.decade===dec).sort((a,b)=>(b.avgWARperYear||0)-(a.avgWARperYear||0)).slice(0,8);
                      setPool(fallback);
                    },800);
                  }}
                  style={{background:teamRerolls>=2?'rgba(30,42,58,0.4)':'rgba(245,158,11,0.06)',border:`1px solid ${teamRerolls>=2?'#0f1f35':'rgba(245,158,11,0.3)'}`,color:teamRerolls>=2?'#1e3a5f':'#f59e0b',borderRadius:8,padding:'8px 18px',cursor:teamRerolls>=2?'not-allowed':'pointer',fontSize:12,fontWeight:700,transition:'all .15s'}}>
                  🔄 New Team {teamRerolls>=2?'(used)':teamRerolls>0?`(${2-teamRerolls} left)`:'(2 left)'}
                </button>
                {!decadeMode&&<button
                  disabled={decadeRerolls>=2}
                  onClick={()=>{
                    if(decadeRerolls>=2) return;
                    // Roll a new decade only — keep the same team, freeze it in the animation
                    const currentDec=spinRes.decade;
                    const allDecs=DECADES.filter(d=>d!==currentDec&&(TEAMS_BY_DECADE[d]||[]).length>0);
                    const newDec=allDecs[Math.floor(Math.random()*allDecs.length)];
                    // Pick a team from that decade (may or may not be same franchise)
                    const teamsInNewDec=TEAMS_BY_DECADE[newDec]||[];
                    const currentTeam=spinRes.team;
                    const draftedIds2=new Set(Object.values(roster).filter(Boolean).map(p=>p.id));
                    const draftedNames2=new Set(Object.values(roster).filter(Boolean).map(p=>(p.displayName||p.name||'').replace(/ \d-yr$/,'')));
                    const notDrafted2=p=>{if(draftedIds2.has(p.id))return false;const dn=(p.displayName||p.name||'').replace(/ \d-yr$/,'');return !draftedNames2.has(dn);};
                    const eligTeams2=(TEAMS_BY_DECADE[newDec]||[]).filter(t=>players.some(p=>notDrafted2(p)&&p.team===t&&p.decade===newDec));
                    const allTeams2=TEAMS_BY_DECADE[newDec]||[];
                    const finalTeam2=(eligTeams2.length>0?eligTeams2:allTeams2)[Math.floor(Math.random()*(eligTeams2.length>0?eligTeams2:allTeams2).length)]||newTeam;
                    const finalRes2={team:finalTeam2,decade:newDec};
                    setDecadeRerolls(r=>r+1);
                    setPool([]);setRerollMode('decade');
                    setSpinning(true);
                    setTimeout(()=>{
                      setSpinRes(finalRes2);setSpinning(false);setRerollMode(null);
                      const strict=players.filter(p=>notDrafted2(p)&&p.team===finalTeam2&&p.decade===newDec).sort((a,b)=>(b.avgWARperYear||0)-(a.avgWARperYear||0));
                      const fallback=strict.length>0?strict:players.filter(p=>notDrafted2(p)&&p.decade===newDec).sort((a,b)=>(b.avgWARperYear||0)-(a.avgWARperYear||0)).slice(0,8);
                      setPool(fallback);
                    },800);
                  }}
                  style={{background:decadeRerolls>=2?'rgba(30,42,58,0.4)':'rgba(96,165,250,0.06)',border:`1px solid ${decadeRerolls>=2?'#0f1f35':'rgba(96,165,250,0.3)'}`,color:decadeRerolls>=2?'#1e3a5f':'#60a5fa',borderRadius:8,padding:'8px 18px',cursor:decadeRerolls>=2?'not-allowed':'pointer',fontSize:12,fontWeight:700,transition:'all .15s'}}>
                  📅 New Decade {decadeRerolls>=2?'(used)':decadeRerolls>0?`(${2-decadeRerolls} left)`:'(2 left)'}
                </button>}
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}
